#include <stdio.h>

int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    int a = 0;
    while (n * m != 0) {
        n--;
        m--;
        a++;
    }
    if (a % 2 == 0) {
        printf("Malvika");
    } else {
        printf("Akshat");
    }
    return 0;
}
