#include <stdio.h>

int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    int a = 0;
    while (n * m != 0) {
        n = n - 1;
        m = m - 1;
        a += 1;
    }
    if (a % 2 == 0) {
        printf("Malvika\n");
    } else {
        printf("Akshat\n");
    }
    return 0;
}
